class Playground {
    async run(inputs) {
        // 1. Initialize data structures
        const heightArray = inputs[0].split(',').map(num => parseInt(num.trim()));
        if (heightArray.some(isNaN)) {
            this.log("Invalid input: Please provide a list of numbers.");
            return 0;
        }

        await this.heights.init(heightArray);
        await this.vars.init([
            ["left", 0],
            ["right", heightArray.length - 1],
            ["maxArea", 0],
            ["currentArea", 0]
        ]);

        let left = 0;
        let right = heightArray.length - 1;
        let maxArea = 0;

        this.log("Starting two-pointer approach from both ends.");
        await this.await();

        while (left < right) {
            // Highlight the current pointers
            this.heights.highlight(left, "#00e0ff"); // Cyan for left
            this.heights.highlight(right, "#ffb703"); // Orange for right

            const hL = this.heights.get(left);
            const hR = this.heights.get(right);
            const width = right - left;
            const currentHeight = Math.min(hL, hR);
            const area = width * currentHeight;

            // Update variables for visualization
            this.vars.put("left", left);
            this.vars.put("right", right);
            this.vars.put("currentArea", area);

            if (area > maxArea) {
                maxArea = area;
                this.vars.put("maxArea", maxArea);
                this.log(`New max area found: min(${hL}, ${hR}) * ${width} = ${area}`);
            } else {
                this.log(`Calculating area: min(${hL}, ${hR}) * ${width} = ${area}`);
            }

            await this.await();

            // Decide which pointer to move
            if (hL < hR) {
                this.log(`Left height (${hL}) is smaller than right height (${hR}). Moving left pointer inward.`);
                this.heights.highlight(left, null);
                left++;
            } else {
                this.log(`Right height (${hR}) is smaller than or equal to left height (${hL}). Moving right pointer inward.`);
                this.heights.highlight(right, null);
                right--;
            }

            await this.await();
        }

        // Final cleanup
        this.heights.highlight(left, null);
        this.heights.highlight(right, null);
        this.log(`Algorithm finished. Maximum water container area is ${maxArea}.`);
        return maxArea;
    }
}
